#include<cstdio>
#include<queue>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=4e5+10,M=4e5+10;
typedef long long LL;const LL INF=0x3f3f3f3f3f3f3f3fll;LL dis[N];
int head[N],des[M<<1],nxt[M<<1],val[M<<1],cgt;
inline void ins(int x,int y,int z)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;val[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;val[cgt]=z;
}
struct EE{int u,v,w,c;}G[M];int PP[M],pp;std::vector<int> OP[M];int n,m;
inline int bnd(int k){int l(1),r(pp),m;while(l<=r)PP[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
struct BB{int f,d;LL m;};struct Seg{int l,r;BB w;}t[N<<5];int Rt[N],cnt;bool dvis[N];
typedef std::pair<LL,int> pli;std::priority_queue<pli,std::vector<pli>,std::greater<pli> > h;
inline void dij()
{
	memset(dis,0x3f,(n+3)*sizeof(dis[0]));memset(dvis,0,(n+3));h.push({dis[1]=0,1});
	while(!h.empty())
	{
		int u=h.top().second;h.pop();if(dvis[u])continue;dvis[u]=true;
		grep(u,i){int v=des[i];if(dis[u]+val[i]<dis[v])h.push({dis[v]=dis[u]+val[i],v});}		
	}
}
inline void build(int &cur,int l=1,int r=n)
{
	cur=++cnt;if(l==r){t[cur].w={l,1,dis[l]};return;}
	int mid=(l+r)>>1;build(t[cur].l,l,mid);build(t[cur].r,mid+1,r);
}
inline void mdy(int cur,int &x,int pos,BB w,int l=1,int r=n)
{
//	if(l==1&&r==n){printf("mdy %d (%d,%d,%lld)\n",pos,w.f,w.d,w.m);}
	t[x=++cnt]=t[cur];if(l==r){t[x].w=w;return;} int mid=(l+r)>>1;
	pos<=mid?mdy(t[cur].l,t[x].l,pos,w,l,mid):mdy(t[cur].r,t[x].r,pos,w,mid+1,r);
}
inline BB qry(int cur,int pos,int l=1,int r=n)
{
	if(l==r)return t[cur].w;int mid=(l+r)>>1;
	return pos<=mid?qry(t[cur].l,pos,l,mid):qry(t[cur].r,pos,mid+1,r); 
}
inline BB fnd(int i,int x){while(true){BB fa=qry(Rt[i],x);if(fa.f==x)return fa;x=fa.f;}}
int fa[N],dep[N];LL mn[N];inline int fnd(int x){while(x!=fa[x])x=fa[x];return x;}
inline void ClearAll(){memset(Rt,0,sizeof(Rt));cnt=0;memset(head,0,sizeof(head));cgt=0;rep(1,m,i)OP[i].clear();}
inline void Solve()
{
	n=read();m=read();ClearAll();
	rep(1,m,i){G[i].u=read();G[i].v=read();G[i].w=read();PP[i]=G[i].c=read();}
	std::sort(PP+1,PP+m+1);pp=std::unique(PP+1,PP+m+1)-PP-1;rep(1,m,i)OP[G[i].c=bnd(G[i].c)].push_back(i);
	rep(1,m,i)ins(G[i].u,G[i].v,G[i].w);dij();build(Rt[pp+1]);rep(1,n,i)fa[i]=i,dep[i]=1,mn[i]=dis[i];
//	rep(1,n,i)printf("%lld ",qry(Rt[pp+1],i).m);puts("");
//	printf("P %d :: ",pp);rep(1,pp,i)printf("%d ",PP[i]);puts("");
	drep(pp,1,i)
	{
		Rt[i]=Rt[i+1];for(int w:OP[i])
		{
//			printf("Ins %d\n",w);
			int u=fnd(G[w].u),v=fnd(G[w].v);if(u==v)continue;if(dep[u]>dep[v]){int tmp=u;u=v;v=tmp;}
			mdy(Rt[i],Rt[i],u,{fa[u]=v,dep[u],mn[u]});mdy(Rt[i],Rt[i],v,{v,dep[v]+=dep[u]==dep[v],mn[v]=min(mn[v],mn[u])});
//			BB qwq=qry(Rt[i],3);//printf("QwQ :: %d %d %lld\n",qwq.f,qwq.d,qwq.m);
		}
	}
	int Q=read(),K=read(),S=read();LL lst=0; while(Q--)
	{
		int s=(read()+K*lst-1)%n+1,i=bnd((read()+K*lst)%(S+1))+1;
//		printf("qry :::::: %d %d\n",i,s);
		printf("%lld\n",lst=(fnd(i,s).m));
//		rep(1,n,i)printf("%lld ",qry(Rt[pp+1],i).m);putchar('\n');
	}
}
int main(){int T=read();while(T--)Solve();}
